import React from 'react'

export default function List({orders,setorders}) {
  

  const change_status=(url)=>{
    console.log(url)
    return new Promise((resolve,reject)=>{
        const axios = require('axios');
        axios.defaults.timeout=6000;
        axios({
            method:'get',
            url:url,
        })
        .then(response=>{
            // alert(response.data)
            if((response.status==200)||(response.status==204))
                resolve(response)
            else 
                reject(response)    
        })
        .catch(err=>reject(err))
    })
}


  const setstatus=(order)=>{
        change_status("/orders/api/"+order.id)
        .then(res=>{
            setorders(orders.map(o=>o.id==order.id ? res.data : o))
        })
        .catch(err=>console.log(err))
}

  return (
    <>
      <div className="container-fluid mt-3">
        <table className="table table-bordered table-striped table-hover">
          <thead>
            <tr>
              <th scope="col">date</th>
              <th scope="col">délégué</th>
              <th scope="col">client</th>
              <th scope="col">produits</th>
              <th scope="col">etat</th>
              <th scope="col">pdf</th>
            </tr>
          </thead>
          <tbody>
            {
              orders.map(order=>
                <tr key={order.id}>
                    <td> {order.added.slice(0,10)}</td>
                    <td> {order.username}</td>
                    <td> {order.medecin.nom}</td>
                    <td>
                    {order.items.map(item=>(
                          <React.Fragment key={item.id}>
                             {item.qtt}) {item.product.nom}  <br/>
                          </React.Fragment>
                            )
                        )}
                    </td>
                    <td> {order.status} <br/> <a onClick={(e)=>setstatus(order)}  className="btn btn-success" >changer etat</a> </td>
                    <td> <a target="_blank" className="btn btn-success" href={"https://app.liliumpharma.com/orders/"+order.id}>PDF</a> </td>
                </tr>
              )
            }
          </tbody>
        </table> 
      </div>   
    </>
  )
}
